<template lang="pug">
  .chats
    .ui.left.aligned.segment.container
      div.fluid
        sui-header(size="large") {{ msg }}
        router-link(to="/")
          img.logo(src="../assets/logo.png")
      .ui.comments
        h3.ui.dividing.header жӯЎиҝҺз•ҷиЁҖ
        .comment(v-for="c in chats" :key="c.time")
          a.avatar
            i.user.icon
          .content
            a.author(:href="'mailto:' + c.email", target="_blank")   {{ c.n }} иӘӘпјҡ
            vue-simple-markdown.text(:source="c.t")
              .metadata
                span.date -{{ parseTime(c.time) }}
      .ui.form
        .two.fields
          .required.field
            label жӮЁзҡ„еӨ§еҗҚ:
            input(type='text' v-model="myName")
          .required.field
            label Email:
            input(type='email' v-model="myEmail")
          .required.field
            label и«Ӣз•ҷиЁҖ:
            input(type='text' v-model="myText" placeholder="жӮЁжғіиӘӘд»Җйәјпјҹ")
        .ui.submit.button(@click="submit(myName, myEmail, myText)") з•ҷиЁҖ
      br
      br

</template>
<script>

export default {
  name: 'Chat',
  props: ['likes', 'chats'],
  data () {
    return {
      msg: 'з•ҷиЁҖзүҲ',
      'myName': 'иЁӘе®ў',
      'myEmail': '',
      'myText': ''
    }
  },
  methods: {
    submit: function (n, email, t) {
      function validateEmail (email) {
        // eslint-disable-next-line
        var re = /^(([^<>()\[\]\\.,;:\s@"]+(\.[^<>()\[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/
        return re.test(String(email).toLowerCase())
      }
      if (!validateEmail(email)) {
        window.alert('и«Ӣијёе…ҘE-mail')
        return
      }
      this.myName = 'иЁӘе®ў'
      this.myEmail = ''
      this.myText = ''
      this.$emit('submit', n, email, t)
    },
    parseTime: function (t) {
      return (new Date(t)).toLocaleDateString()
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>

.fluid {
  text-align: center;
  width:100%;
}
</style>



